SELECT a.id, a.applicant_user_id, a.image_id, a.apply_reason, a.status, a.reviewer_user_id, (SELECT username FROM sys_user WHERE id = a.reviewer_user_id) AS reviewer_username, a.reject_reason, a.create_time, a.review_time, i.filename, i.oss_url FROM biz_image_audit_record a LEFT JOIN biz_image i ON i.id = a.image_id
a.status = #{status}
ORDER BY a.create_time ASC
